<body><table width="100%"><tr><td><strong>{{ $sale->company->name ?? 'RetailPOS' }}</strong><h1>POS Receipt</h1><p>{{ $sale->branch?->name }}<br>{{ $sale->branch?->address }}</p></td><td class="right"><strong>{{ $sale->receipt_number ?: $sale->sale_number }}</strong><br>{{ $sale->completed_at?->format('d M Y, h:i A') }}<br>{{ $sale->register?->name }}</td></tr></table>
